import { useState } from 'react'
import styled, { css } from 'styled-components'

import { ContactDetails } from './ContactDetails'
import { DeliveryDetails } from './DeliveryDetails'
import { StepIndicator } from './StepIndicator'
import { type ContactDetailsFormData, type DeliveryDetailsFormData } from './validation'

type Step = {
  id: 'Contact details' | 'Delivery details'
}

const steps: Step[] = [{ id: 'Contact details' }, { id: 'Delivery details' }]

const defaultData: ContactDetailsFormData & DeliveryDetailsFormData = {
  firstName: '',
  lastName: '',
  address: '',
  city: '',
  postcode: '',
  email: '',
  phone: '',
}

const FormContainer = styled.div(
  ({ theme: { color, borderRadius } }) => css`
    width: 100%;
    min-height: 480px;
    margin-right: 1.5rem;
    background: ${color.formBackground};
    padding: 1.5rem;
    border-radius: ${borderRadius.s};
  `
)

export const MultiStepForm = () => {
  const [currentStep, setCurrentStep] = useState(0)
  const [formData, setFormData] = useState(defaultData)

  const handleNext = () => {
    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1)
    }
  }

  const handlePrevious = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1)
    }
  }

  const handleFormData = (data: Partial<typeof defaultData>) => {
    setFormData((prev) => ({ ...prev, ...data }))
  }

  const currentStepData = steps[currentStep]

  const renderCurrentStep = () => {
    switch (currentStepData.id) {
      case 'Contact details': {
        return (
          <ContactDetails formData={formData} setFormData={handleFormData} onNext={handleNext} />
        )
      }
      case 'Delivery details': {
        return (
          <DeliveryDetails
            formData={formData}
            setFormData={handleFormData}
            onPrevious={handlePrevious}
          />
        )
      }
      default: {
        return null
      }
    }
  }

  return (
    <FormContainer>
      <StepIndicator
        title={currentStepData.id}
        currentStep={currentStep + 1}
        amountOfSteps={steps.length}
      />
      {renderCurrentStep()}
    </FormContainer>
  )
}
import { useState, ChangeEvent } from 'react'
import styled, { css } from 'styled-components'

import { Button } from '../../../../components/Button'
import { Input } from '../../../../components/forms/Input'
import { Body } from '../../../../components/typography/Body'
import { type ContactDetailsFormData } from './validation'

const DisclaimerText = styled(Body)(
  ({ theme: { spacing } }) => css`
    margin-bottom: ${spacing.m};
  `
)

type ContactDetailsProps = {
  formData: ContactDetailsFormData
  setFormData: (data: Partial<ContactDetailsFormData>) => void
  onNext: () => void
}

type FormErrors = {
  [K in keyof ContactDetailsFormData]?: string
}

const contactFields: (keyof ContactDetailsFormData)[] = ['firstName', 'lastName', 'email', 'phone']

export const ContactDetails = ({ formData, setFormData, onNext }: ContactDetailsProps) => {
  const [errors, setErrors] = useState<FormErrors>({})
  const [form, setForm] = useState<ContactDetailsFormData>(formData)
  const [isSubmitted, setIsSubmitted] = useState(false)

  const validateField = (name: keyof ContactDetailsFormData, value: string): string | undefined => {
    if (!value) return 'Required'

    switch (name) {
      case 'firstName':
      case 'lastName': {
        return value.length < 2 ? 'Must be at least 2 characters' : undefined
      }
      case 'email': {
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)
          ? undefined
          : 'Please enter a valid email address'
      }
      case 'phone': {
        return value.length < 10 ? 'Please enter a valid phone number' : undefined
      }
      default: {
        return undefined
      }
    }
  }

  const handleChange = (e: ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target
    setForm((prev) => ({ ...prev, [name]: value }))

    if (isSubmitted) {
      const error = validateField(name as keyof ContactDetailsFormData, value)
      setErrors((prev) => ({
        ...prev,
        [name]: error,
      }))
    }
  }

  const handleNext = () => {
    setIsSubmitted(true)

    // Validate only contact fields
    const newErrors: FormErrors = {}
    let hasErrors = false

    for (const field of contactFields) {
      const error = validateField(field, form[field])
      if (error) {
        newErrors[field] = error
        hasErrors = true
      }
    }

    setErrors(newErrors)

    if (!hasErrors) {
      setFormData(form)
      onNext()
    }
  }

  return (
    <div className="form">
      <Input
        label="First name"
        placeholder="John"
        name="firstName"
        value={form.firstName}
        onChange={handleChange}
        error={isSubmitted ? errors.firstName : undefined}
      />
      <Input
        label="Last name"
        placeholder="Doe"
        name="lastName"
        value={form.lastName}
        onChange={handleChange}
        error={isSubmitted ? errors.lastName : undefined}
      />
      <Input
        label="Email"
        type="email"
        placeholder="email address"
        name="email"
        value={form.email}
        onChange={handleChange}
        error={isSubmitted ? errors.email : undefined}
      />
      <Input
        label="Phone number"
        placeholder="phone number"
        type="tel"
        name="phone"
        value={form.phone}
        onChange={handleChange}
        error={isSubmitted ? errors.phone : undefined}
      />
      <DisclaimerText size="XXS" type="span">
        We'll only use your phone to call you about your order
      </DisclaimerText>
      <div style={{ display: 'flex', justifyContent: 'flex-start' }}>
        <Button onClick={handleNext}>Next</Button>
      </div>
    </div>
  )
}
import { useState, ChangeEvent } from 'react'
import { useNavigate } from 'react-router-dom'

import { saveOrderAction } from '../../../../app-state/order'
import { useAppDispatch, useAppSelector } from '../../../../app-state'
import { clearCartAction, selectCartItems } from '../../../../app-state/cart'
import { Button } from '../../../../components/Button'
import { Input } from '../../../../components/forms/Input'
import { type DeliveryDetailsFormData } from './validation'

type DeliveryDetailsProps = {
  formData: DeliveryDetailsFormData
  setFormData: (data: Partial<DeliveryDetailsFormData>) => void
  onPrevious: () => void
}

type FormErrors = {
  [K in keyof DeliveryDetailsFormData]?: string
}

const deliveryFields: (keyof DeliveryDetailsFormData)[] = ['address', 'city', 'postcode']

export const DeliveryDetails = ({ formData, setFormData, onPrevious }: DeliveryDetailsProps) => {
  const navigate = useNavigate()
  const dispatch = useAppDispatch()
  const cartItems = useAppSelector(selectCartItems)
  const [errors, setErrors] = useState<FormErrors>({})
  const [form, setForm] = useState<DeliveryDetailsFormData>(formData)
  const [isSubmitted, setIsSubmitted] = useState(false)

  const validateField = (
    name: keyof DeliveryDetailsFormData,
    value: string
  ): string | undefined => {
    if (!value) return 'Required'

    switch (name) {
      case 'address': {
        return value.length < 5 ? 'Please enter a valid address' : undefined
      }
      case 'city': {
        return value.length < 2 ? 'Please enter a valid city' : undefined
      }
      case 'postcode': {
        return /^[0-9]{4}[A-Z]{2}$/.test(value)
          ? undefined
          : 'Please enter a valid postcode (e.g., 1234AB)'
      }
      default: {
        return undefined
      }
    }
  }

  const handleChange = (e: ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target
    setForm((prev) => ({ ...prev, [name]: value }))

    if (isSubmitted) {
      const error = validateField(name as keyof DeliveryDetailsFormData, value)
      setErrors((prev) => ({
        ...prev,
        [name]: error,
      }))
    }
  }

  const handleComplete = () => {
    setIsSubmitted(true)

    // Validate only delivery fields
    const newErrors: FormErrors = {}
    let hasErrors = false

    for (const field of deliveryFields) {
      const error = validateField(field, form[field])
      if (error) {
        newErrors[field] = error
        hasErrors = true
      }
    }

    setErrors(newErrors)

    if (!hasErrors) {
      setFormData(form)
      dispatch(saveOrderAction(cartItems))
      dispatch(clearCartAction())
      navigate('/success')
    }
  }

  return (
    <div className="form">
      <Input
        label="Streetname and housenumber"
        placeholder="Some street, 13"
        name="address"
        value={form.address}
        onChange={handleChange}
        error={isSubmitted ? errors.address : undefined}
      />
      <Input
        label="Postcode"
        placeholder="AAAAXX"
        name="postcode"
        value={form.postcode}
        onChange={handleChange}
        error={isSubmitted ? errors.postcode : undefined}
      />
      <Input
        label="City"
        placeholder="Amsterdam"
        name="city"
        value={form.city}
        onChange={handleChange}
        error={isSubmitted ? errors.city : undefined}
      />
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
        }}
      >
        <Button clear onClick={onPrevious}>
          Previous
        </Button>
        <Button onClick={handleComplete}>Complete order</Button>
      </div>
    </div>
  )
}

