import styled, { useTheme } from 'styled-components'

const StyledSVG = styled.svg`
  display: block;
`

export type IconName =
  | 'arrow-right'
  | 'arrow-left'
  | 'cross'
  | 'cart'
  | 'minus'
  | 'plus'
  | 'moon'
  | 'sun'
  | 'star'

type IconProps = {
  name: IconName
  color?: string
  size?: number | string
}

export const Icon = ({ name, color, size = '1.5rem' }: IconProps) => {
  const { color: themeColor } = useTheme()
  return (
    <StyledSVG
      stroke={color || themeColor.primaryText}
      width={size}
      height={size}
      style={{ minWidth: size }}
    >
      <use xlinkHref={`/sprite-map.svg#${name}`} />
    </StyledSVG>
  )
}
import type { ComponentProps } from 'react'
import styled, { css } from 'styled-components'

import { Icon, IconName } from '../Icon'

const StyledButton = styled.button<{ $small: boolean }>(
  ({ $small, theme: { borderRadius } }) => css`
    border: 0;
    width: ${$small ? '3rem' : '4rem'};
    height: ${$small ? '3rem' : '4rem'};
    border-radius: ${borderRadius.round};
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 14px;
    color: #333;
    background-color: white;
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.14);
  `
)

type IconButtonProps = {
  name: IconName
  small?: boolean
  onClick?: () => void
} & Omit<ComponentProps<'button'>, 'name' | 'small'>

export const IconButton = ({ small = false, name, ...props }: IconButtonProps) => {
  return (
    <StyledButton type="button" $small={small} {...props}>
      <Icon name={name} size={small ? 15 : 24} color="#202020" />
    </StyledButton>
  )
}

